<?php
namespace App\Http\Controllers\Admin\Content;use App\Domain\Shops\Admin\ShopAdminReadService;use App\Domain\Shops\Admin\ShopOfferAdminService;use App\Http\Controllers\Controller;use App\Http\Requests\Admin\Content\ShopOfferRequest;use App\Models\Shop;use App\Models\ShopOffer;use Illuminate\Http\Request;use InvalidArgumentException;
final class ShopOfferController extends Controller{public function search(Request $request,ShopAdminReadService $read){$term=trim((string)$request->query('q',''));return response()->json(['data'=>$term===''?[]:$read->searchItems(mb_substr($term,0,100))->all()]);}public function store(ShopOfferRequest $request,Shop $shop,ShopOfferAdminService $service){return$this->save($request,$shop,null,$service,'Oferta creada correctamente.');}public function update(ShopOfferRequest $request,Shop $shop,ShopOffer $offer,ShopOfferAdminService $service){return$this->save($request,$shop,$offer,$service,'Oferta actualizada correctamente.');}public function activate(Shop $shop,ShopOffer $offer,ShopOfferAdminService $service){return$this->status(function()use($service,$shop,$offer){$service->activate($shop,$offer);},'Oferta activada correctamente.');}public function deactivate(Shop $shop,ShopOffer $offer,ShopOfferAdminService $service){return$this->status(function()use($service,$shop,$offer){$service->deactivate($shop,$offer);},'Oferta desactivada correctamente.');}private function save($request,$shop,$offer,$service,$message){try{$service->save($shop,$request->validated(),$offer);return redirect()->route('admin.content.shops.edit',$shop)->with('status',$message);}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['offer'=>$e->getMessage()]);}}private function status($callback,$message){try{$callback();return back()->with('status',$message);}catch(InvalidArgumentException $e){return back()->withErrors(['offer'=>$e->getMessage()]);}}}
